use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract metadata from the PDF
sub extract_metadata {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $info = $pdf->info;
    my $author = $info->get('Author') || 'Unknown';
    my $title = $info->get('Title') || 'Unknown';
    my $creation_date = $info->get('CreationDate') || 'Unknown';

    return $author, $title, $creation_date;
}

# Function to extract text from the PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = '';

    for my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->open_page($page);
        $text .= $page_obj->text;
    }

    return $text;
}

